export interface CommentMetadata {
  browser: {
    name: string
    version: string
    userAgent: string
  }
  os: {
    name: string
    version: string
  }
  viewport: {
    width: number
    height: number
    devicePixelRatio: number
  }
  page: {
    url: string
    path: string
    title: string
  }
  user: {
    timezone: string
    language: string
    colorScheme: 'light' | 'dark'
  }
  timestamp: string
}

export function captureMetadata(): CommentMetadata {
  const userAgent = navigator.userAgent
  const browser = parseBrowser(userAgent)
  const os = parseOS(userAgent)

  return {
    browser,
    os,
    viewport: {
      width: window.innerWidth,
      height: window.innerHeight,
      devicePixelRatio: window.devicePixelRatio || 1
    },
    page: {
      url: window.location.href,
      path: window.location.pathname,
      title: document.title
    },
    user: {
      timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
      language: navigator.language,
      colorScheme: window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light'
    },
    timestamp: new Date().toISOString()
  }
}

function parseBrowser(userAgent: string): { name: string; version: string; userAgent: string } {
  let name = 'Unknown'
  let version = 'Unknown'

  // Chrome
  if (userAgent.includes('Chrome/') && !userAgent.includes('Edg/')) {
    name = 'Chrome'
    const match = userAgent.match(/Chrome\/(\d+\.\d+)/)
    if (match) version = match[1]
  }
  // Firefox
  else if (userAgent.includes('Firefox/')) {
    name = 'Firefox'
    const match = userAgent.match(/Firefox\/(\d+\.\d+)/)
    if (match) version = match[1]
  }
  // Safari
  else if (userAgent.includes('Safari/') && !userAgent.includes('Chrome/')) {
    name = 'Safari'
    const match = userAgent.match(/Version\/(\d+\.\d+)/)
    if (match) version = match[1]
  }
  // Edge
  else if (userAgent.includes('Edg/')) {
    name = 'Edge'
    const match = userAgent.match(/Edg\/(\d+\.\d+)/)
    if (match) version = match[1]
  }

  return { name, version, userAgent }
}

function parseOS(userAgent: string): { name: string; version: string } {
  let name = 'Unknown'
  let version = 'Unknown'

  // Windows
  if (userAgent.includes('Windows NT')) {
    name = 'Windows'
    const match = userAgent.match(/Windows NT (\d+\.\d+)/)
    if (match) {
      const ntVersion = match[1]
      const windowsVersionMap: { [key: string]: string } = {
        '10.0': '10/11',
        '6.3': '8.1',
        '6.2': '8',
        '6.1': '7'
      }
      version = windowsVersionMap[ntVersion] || ntVersion
    }
  }
  // macOS
  else if (userAgent.includes('Mac OS X')) {
    name = 'macOS'
    const match = userAgent.match(/Mac OS X (\d+[._]\d+([._]\d+)?)/)
    if (match) {
      version = match[1].replace(/_/g, '.')
    }
  }
  // Linux
  else if (userAgent.includes('Linux')) {
    name = 'Linux'
    if (userAgent.includes('Ubuntu')) version = 'Ubuntu'
    else if (userAgent.includes('Android')) {
      name = 'Android'
      const match = userAgent.match(/Android (\d+\.\d+)/)
      if (match) version = match[1]
    }
  }
  // iOS
  else if (userAgent.includes('iPhone OS') || userAgent.includes('OS ')) {
    name = 'iOS'
    const match = userAgent.match(/OS (\d+[._]\d+([._]\d+)?)/)
    if (match) {
      version = match[1].replace(/_/g, '.')
    }
  }

  return { name, version }
}