import html2canvas from 'html2canvas'

export async function captureElementScreenshot(element: HTMLElement): Promise<string> {
  try {
    // Configure html2canvas options
    const canvas = await html2canvas(element, {
      allowTaint: true,
      useCORS: true,
      scale: 1,
      backgroundColor: null,
      removeContainer: true,
      imageTimeout: 5000,
      width: element.offsetWidth,
      height: element.offsetHeight
    })

    // Convert canvas to blob
    return new Promise((resolve, reject) => {
      canvas.toBlob((blob) => {
        if (!blob) {
          reject(new Error('Failed to create blob from canvas'))
          return
        }

        // Create object URL for the blob
        const url = URL.createObjectURL(blob)
        resolve(url)
      }, 'image/png', 0.9)
    })
  } catch (error) {
    console.error('Error capturing screenshot:', error)
    throw error
  }
}

export async function uploadScreenshot(blob: Blob, supabaseClient: any, bucket: string = 'screenshots'): Promise<string> {
  try {
    const fileName = `screenshot-${Date.now()}-${Math.random().toString(36).substring(7)}.png`
    const { data, error } = await supabaseClient.storage
      .from(bucket)
      .upload(fileName, blob, {
        contentType: 'image/png',
        cacheControl: '3600'
      })

    if (error) throw error

    // Get public URL
    const { data: publicData } = supabaseClient.storage
      .from(bucket)
      .getPublicUrl(fileName)

    return publicData.publicUrl
  } catch (error) {
    console.error('Error uploading screenshot:', error)
    throw error
  }
}

export function blobToDataURL(blob: Blob): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new FileReader()
    reader.onload = () => resolve(reader.result as string)
    reader.onerror = reject
    reader.readAsDataURL(blob)
  })
}