  private async createComment(element: HTMLElement, content: string, x: number, y: number): Promise<void> {
    try {
      // Capture element metadata
      const selector = this.getElementSelector(element)
      const xpath = this.getElementXPath(element)
      const parentChain = this.getElementParentChain(element)
      const metadata = captureMetadata()

      // Capture screenshot
      let screenshotUrl: string | undefined
      try {
        const blobUrl = await captureElementScreenshot(element)
        // Convert blob URL to actual blob
        const response = await fetch(blobUrl)
        const blob = await response.blob()
        // Upload to Supabase Storage
        screenshotUrl = await uploadScreenshot(blob, this.supabase)
        // Clean up blob URL
        URL.revokeObjectURL(blobUrl)
      } catch (error) {
        console.warn('Failed to capture and upload screenshot:', error)
      }

      // Create comment in database
      const { data, error } = await this.supabase
        .from('comments')
        .insert({
          project_id: this.projectId,
          page_id: null, // For agentic mode, we don't have page_id
          content,
          x,
          y,
          element_selector: selector,
          element_xpath: xpath,
          element_parent_chain: parentChain,
          element_screenshot_url: screenshotUrl,
          page_path: window.location.pathname,
          metadata
        })
        .select()
        .single()

      if (error) throw error

      // Add to local comments and re-render pins
      this.comments.push(data)
      this.renderCommentPins()

    } catch (error) {
      console.error('Error creating comment:', error)
      alert('Failed to create comment: ' + (error as Error).message)
    }
  }

  private getElementSelector(element: HTMLElement): string {
    // Generate CSS selector for element
    const path: string[] = []
    let current = element

    while (current && current !== document.body) {
      let selector = current.tagName.toLowerCase()

      if (current.id) {
        selector += `#${current.id}`
        path.unshift(selector)
        break
      }

      if (current.className) {
        const classes = current.className.split(' ').filter(Boolean)
        if (classes.length > 0) {
          selector += '.' + classes.join('.')
        }
      }

      const siblings = Array.from(current.parentElement?.children || [])
        .filter(sibling => sibling.tagName === current.tagName)

      if (siblings.length > 1) {
        const index = siblings.indexOf(current)
        selector += `:nth-of-type(${index + 1})`
      }

      path.unshift(selector)
      current = current.parentElement as HTMLElement
    }

    return path.join(' > ')
  }

  private getElementXPath(element: HTMLElement): string {
    const path: string[] = []
    let current = element

    while (current && current !== document.body) {
      let index = 1
      let sibling = current.previousElementSibling

      while (sibling) {
        if (sibling.tagName === current.tagName) {
          index++
        }
        sibling = sibling.previousElementSibling
      }

      const tagName = current.tagName.toLowerCase()
      path.unshift(`${tagName}[${index}]`)
      current = current.parentElement as HTMLElement
    }

    return '/' + path.join('/')
  }

  private getElementParentChain(element: HTMLElement): string[] {
    const chain: string[] = []
    let current = element.parentElement

    while (current && current !== document.body) {
      chain.push(this.getElementSelector(current))
      current = current.parentElement
    }

    return chain
  }

  private async loadComments(): Promise<void> {
    try {
      const { data, error } = await this.supabase
        .from('comments')
        .select('*')
        .eq('project_id', this.projectId)
        .eq('page_path', window.location.pathname)

      if (error) throw error

      this.comments = data || []
    } catch (error) {
      console.error('Error loading comments:', error)
    }
  }

  private renderCommentPins(): void {
    if (!this.overlay) return

    // Clear existing pins
    this.overlay.innerHTML = ''

    this.comments.forEach(comment => {
      if (!comment.element_selector) return

      // Try to find element using selector
      let targetElement = document.querySelector(comment.element_selector)

      // If element not found, try parent chain fallback
      if (!targetElement && comment.element_parent_chain) {
        for (const parentSelector of comment.element_parent_chain) {
          targetElement = document.querySelector(parentSelector)
          if (targetElement) break
        }
      }

      if (!targetElement) return

      // Get element position
      const rect = targetElement.getBoundingClientRect()

      // Create comment pin
      const pin = document.createElement('div')
      pin.style.cssText = `
        position: absolute;
        left: ${rect.left + window.scrollX}px;
        top: ${rect.top + window.scrollY}px;
        width: 24px;
        height: 24px;
        background: #3b82f6;
        border-radius: 50%;
        border: 2px solid white;
        cursor: pointer;
        pointer-events: all;
        z-index: 1000001;
        display: flex;
        align-items: center;
        justify-content: center;
        color: white;
        font-size: 12px;
        font-weight: bold;
        box-shadow: 0 2px 8px rgba(0, 0, 0, 0.2);
      `
      pin.textContent = '💬'

      // Add click handler to show comment
      pin.addEventListener('click', () => {
        this.showCommentDetails(comment)
      })

      this.overlay?.appendChild(pin)
    })
  }

