import { SupabaseClient } from '@supabase/supabase-js'

export interface ToolbarConfig {
  position: 'top-right' | 'bottom-right' | 'top-left' | 'bottom-left'
  user?: {
    id: string
    email: string
    avatarUrl?: string
  }
  projectId: string
}

export interface ToolbarData {
  commentCount: number
  activeComments: number
  previewComments: number
  deployedComments: number
}

export class ToolbarModule {
  private supabase: SupabaseClient
  private config: ToolbarConfig
  private toolbar?: HTMLElement
  private data: ToolbarData = {
    commentCount: 0,
    activeComments: 0,
    previewComments: 0,
    deployedComments: 0
  }
  private isVisible = false
  private isExpanded = false

  constructor(supabase: SupabaseClient, config: ToolbarConfig) {
    this.supabase = supabase
    this.config = config
  }

  async init(): Promise<void> {
    if (this.toolbar) return

    this.createToolbar()
    await this.loadData()
    this.attachEventListeners()
    this.show()
  }

  destroy(): void {
    if (this.toolbar) {
      document.body.removeChild(this.toolbar)
      this.toolbar = undefined
    }
    this.removeEventListeners()
    this.isVisible = false
    this.isExpanded = false
  }

  private createToolbar(): void {
    this.toolbar = document.createElement('div')
    this.toolbar.id = 'vibe-toolbar'

    // Position styles based on config
    const positionStyles = this.getPositionStyles()

    this.toolbar.style.cssText = `
      position: fixed;
      ${positionStyles}
      z-index: 999997;
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      opacity: 0;
      transform: scale(0.8) ${this.getTransformDirection()};
      transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
      pointer-events: none;
    `

    // Add global styles if not present
    if (!document.getElementById('vibe-toolbar-styles')) {
      this.addToolbarStyles()
    }

    this.renderToolbar()
    document.body.appendChild(this.toolbar)
  }

  private addToolbarStyles(): void {
    const styles = document.createElement('style')
    styles.id = 'vibe-toolbar-styles'
    styles.textContent = `
      .vibe-toolbar-visible {
        opacity: 1 !important;
        transform: scale(1) translate(0) !important;
        pointer-events: auto !important;
      }

      .vibe-toolbar-btn {
        transition: all 0.2s ease;
        cursor: pointer;
        border: none;
        background: transparent;
        display: flex;
        align-items: center;
        justify-content: center;
        position: relative;
      }

      .vibe-toolbar-btn:hover {
        transform: scale(1.05);
      }

      .vibe-toolbar-btn:active {
        transform: scale(0.95);
      }

      .vibe-toolbar-badge {
        position: absolute;
        top: -4px;
        right: -4px;
        background: #ef4444;
        color: white;
        border-radius: 50%;
        width: 16px;
        height: 16px;
        font-size: 10px;
        font-weight: bold;
        display: flex;
        align-items: center;
        justify-content: center;
        border: 2px solid white;
        min-width: 16px;
        box-sizing: border-box;
      }

      .vibe-toolbar-expanded {
        animation: expandToolbar 0.3s ease-out;
      }

      .vibe-toolbar-collapsed {
        animation: collapseToolbar 0.3s ease-out;
      }

      @keyframes expandToolbar {
        from { max-width: 56px; }
        to { max-width: 300px; }
      }

      @keyframes collapseToolbar {
        from { max-width: 300px; }
        to { max-width: 56px; }
      }

      .vibe-fade-in {
        animation: vibeToolbarFadeIn 0.3s ease-out;
      }

      @keyframes vibeToolbarFadeIn {
        from { opacity: 0; transform: translateX(10px); }
        to { opacity: 1; transform: translateX(0); }
      }
    `
    document.head.appendChild(styles)
  }

  private getPositionStyles(): string {
    const margin = '20px'

    switch (this.config.position) {
      case 'top-right':
        return `top: ${margin}; right: ${margin};`
      case 'bottom-right':
        return `bottom: ${margin}; right: ${margin};`
      case 'top-left':
        return `top: ${margin}; left: ${margin};`
      case 'bottom-left':
        return `bottom: ${margin}; left: ${margin};`
      default:
        return `bottom: ${margin}; right: ${margin};`
    }
  }

  private getTransformDirection(): string {
    switch (this.config.position) {
      case 'top-right':
        return 'translate(10px, -10px)'
      case 'bottom-right':
        return 'translate(10px, 10px)'
      case 'top-left':
        return 'translate(-10px, -10px)'
      case 'bottom-left':
        return 'translate(-10px, 10px)'
      default:
        return 'translate(10px, 10px)'
    }
  }

  private renderToolbar(): void {
    if (!this.toolbar) return

    const isCollapsed = !this.isExpanded

    this.toolbar.innerHTML = `
      <div class="vibe-toolbar-container" style="
        background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
        border-radius: 28px;
        padding: 8px;
        box-shadow: 0 8px 25px rgba(0, 0, 0, 0.15);
        backdrop-filter: blur(10px);
        display: flex;
        align-items: center;
        gap: 8px;
        max-width: ${isCollapsed ? '56px' : '300px'};
        overflow: hidden;
        transition: all 0.3s ease;
      ">
        <!-- Main Toggle Button -->
        <button class="vibe-toolbar-btn vibe-main-btn" style="
          width: 40px;
          height: 40px;
          border-radius: 50%;
          background: rgba(255, 255, 255, 0.1);
          backdrop-filter: blur(8px);
          color: white;
          font-size: 16px;
          position: relative;
          flex-shrink: 0;
        ">
          💬
          ${this.data.commentCount > 0 ? `
            <div class="vibe-toolbar-badge">${this.formatCount(this.data.commentCount)}</div>
          ` : ''}
        </button>

        <!-- Expanded Content -->
        <div class="vibe-toolbar-content" style="
          display: ${isCollapsed ? 'none' : 'flex'};
          align-items: center;
          gap: 12px;
          color: white;
          min-width: 0;
          flex: 1;
        ">
          <!-- Comments Summary -->
          <div class="vibe-comments-summary" style="
            display: flex;
            flex-direction: column;
            gap: 2px;
            min-width: 0;
            flex: 1;
          ">
            <div style="font-size: 12px; font-weight: 600;">
              ${this.data.commentCount} comment${this.data.commentCount !== 1 ? 's' : ''}
            </div>
            <div style="font-size: 10px; opacity: 0.8;">
              ${this.data.activeComments} active • ${this.data.previewComments} preview • ${this.data.deployedComments} deployed
            </div>
          </div>

          <!-- Action Buttons -->
          <div style="display: flex; gap: 6px; flex-shrink: 0;">
            <!-- User Avatar -->
            ${this.config.user ? `
              <button class="vibe-toolbar-btn" title="User Settings" style="
                width: 28px;
                height: 28px;
                border-radius: 50%;
                background: rgba(255, 255, 255, 0.1);
                overflow: hidden;
                color: white;
                font-size: 12px;
              ">
                ${this.config.user.avatarUrl ? `
                  <img src="${this.config.user.avatarUrl}" style="
                    width: 100%;
                    height: 100%;
                    object-fit: cover;
                  " />
                ` : this.getInitials(this.config.user.email)}
              </button>
            ` : ''}

            <!-- Settings -->
            <button class="vibe-toolbar-btn vibe-settings-btn" title="Settings" style="
              width: 28px;
              height: 28px;
              border-radius: 50%;
              background: rgba(255, 255, 255, 0.1);
              color: white;
              font-size: 12px;
            ">
              ⚙️
            </button>

            <!-- Close -->
            <button class="vibe-toolbar-btn vibe-close-btn" title="Close" style="
              width: 28px;
              height: 28px;
              border-radius: 50%;
              background: rgba(255, 255, 255, 0.1);
              color: white;
              font-size: 12px;
              line-height: 1;
            ">
              ×
            </button>
          </div>
        </div>
      </div>
    `

    this.attachButtonListeners()
  }

  private attachButtonListeners(): void {
    if (!this.toolbar) return

    // Main button - toggle expansion and open comments
    const mainBtn = this.toolbar.querySelector('.vibe-main-btn')
    mainBtn?.addEventListener('click', () => {
      if (!this.isExpanded) {
        this.expand()
      } else {
        this.openCommentsList()
      }
    })

    // Settings button
    const settingsBtn = this.toolbar.querySelector('.vibe-settings-btn')
    settingsBtn?.addEventListener('click', (e) => {
      e.stopPropagation()
      this.openSettings()
    })

    // Close button
    const closeBtn = this.toolbar.querySelector('.vibe-close-btn')
    closeBtn?.addEventListener('click', (e) => {
      e.stopPropagation()
      this.hide()
    })

    // User avatar button
    const userBtn = this.toolbar.querySelector('.vibe-toolbar-btn[title="User Settings"]')
    userBtn?.addEventListener('click', (e) => {
      e.stopPropagation()
      this.openUserSettings()
    })
  }

  private attachEventListeners(): void {
    // Listen for clicks outside toolbar to collapse
    document.addEventListener('click', this.handleOutsideClick.bind(this))

    // Listen for comment events
    window.addEventListener('vibe:commentsUpdated', this.handleCommentsUpdated.bind(this))
    window.addEventListener('vibe:openCommentsList', this.openCommentsList.bind(this))
  }

  private removeEventListeners(): void {
    document.removeEventListener('click', this.handleOutsideClick.bind(this))
    window.removeEventListener('vibe:commentsUpdated', this.handleCommentsUpdated.bind(this))
    window.removeEventListener('vibe:openCommentsList', this.openCommentsList.bind(this))
  }

  private handleOutsideClick(event: MouseEvent): void {
    if (!this.toolbar || !this.isExpanded) return

    const target = event.target as Element
    if (!this.toolbar.contains(target)) {
      this.collapse()
    }
  }

  private async handleCommentsUpdated(): Promise<void> {
    await this.loadData()
    this.renderToolbar()
  }

  private async loadData(): Promise<void> {
    try {
      const { data: comments, error } = await this.supabase
        .from('comments')
        .select(`
          id,
          status,
          page_path,
          created_at
        `)
        .eq('project_id', this.config.projectId)

      if (error) throw error

      // Count comments by status
      const total = comments?.length || 0
      const active = comments?.filter(c => !c.status || c.status === 'active').length || 0
      const preview = comments?.filter(c => c.status === 'preview').length || 0
      const deployed = comments?.filter(c => c.status === 'deployed').length || 0

      this.data = {
        commentCount: total,
        activeComments: active,
        previewComments: preview,
        deployedComments: deployed
      }
    } catch (error) {
      console.error('Error loading toolbar data:', error)
    }
  }

  private expand(): void {
    this.isExpanded = true
    this.renderToolbar()
  }

  private collapse(): void {
    this.isExpanded = false
    this.renderToolbar()
  }

  private openCommentsList(): void {
    // Emit event for comment list to open
    const event = new CustomEvent('vibe:openCommentsList', {
      detail: { projectId: this.config.projectId }
    })
    window.dispatchEvent(event)
  }

  private openSettings(): void {
    // Emit event for settings modal
    const event = new CustomEvent('vibe:openSettings', {
      detail: { projectId: this.config.projectId }
    })
    window.dispatchEvent(event)
  }

  private openUserSettings(): void {
    // Emit event for user settings
    const event = new CustomEvent('vibe:openUserSettings', {
      detail: { user: this.config.user }
    })
    window.dispatchEvent(event)
  }

  private show(): void {
    if (!this.toolbar || this.isVisible) return

    this.isVisible = true
    this.toolbar.classList.add('vibe-toolbar-visible')
  }

  private hide(): void {
    if (!this.toolbar || !this.isVisible) return

    this.isVisible = false
    this.toolbar.classList.remove('vibe-toolbar-visible')

    // Hide completely after transition
    setTimeout(() => {
      if (this.toolbar && !this.isVisible) {
        this.toolbar.style.display = 'none'
      }
    }, 300)
  }

  // Helper methods
  private formatCount(count: number): string {
    if (count > 99) return '99+'
    return count.toString()
  }

  private getInitials(email: string): string {
    const parts = email.split('@')[0].split('.')
    if (parts.length >= 2) {
      return (parts[0][0] + parts[1][0]).toUpperCase()
    }
    return email.substring(0, 2).toUpperCase()
  }

  // Public methods
  updateConfig(config: Partial<ToolbarConfig>): void {
    this.config = { ...this.config, ...config }
    this.renderToolbar()
  }

  async refresh(): Promise<void> {
    await this.loadData()
    this.renderToolbar()
  }

  toggle(): void {
    if (this.isVisible) {
      this.hide()
    } else {
      this.show()
    }
  }

  isToolbarVisible(): boolean {
    return this.isVisible
  }

  getData(): ToolbarData {
    return { ...this.data }
  }
}